sql:
SELECT SUM(budget_amount) AS total_budget, AVG(production_cost) AS average_production_cost
FROM film_budgets
WHERE year = 2009;

external_knowledge:
- "Past two decades" refers to the years between 2000 and 2020;
- "Half a billion dollars" is 500,000,000 USD;
- "Revenue" refers to the total amount of money earned from the film.

sql:
SELECT name 
FROM cast_and_crew 
WHERE role = 'Director' AND department = 'Directing';

external_knowledge:
- "highest praise" refers to the highest-rated rating for a film;
- "crowned as the favorites" refers to films with the highest-rated rating;
- "box office treasure" refers to the total revenue earned by the films.

sql:
SELECT DISTINCT title
FROM films
ORDER BY title ASC;

external_knowledge:
- "Box office giants" refers to films with a total revenue greater than 100 million dollars;
- "Financial triumphs" refers to the total revenue of the films;
- "Critical acclaim" refers to the average rating of the films.

- "shining stars" refers to films with the highest gross revenue;
- "top the box office charts" means ranking first in terms of gross revenue;
- "respective genres" indicates that the ranking is done within each genre.

- 'Top 10 highest-grossing films' refers to films with the highest gross revenue;
- 'Average ratings' are calculated by averaging the rating values for each film;
- 'Streaming revenues' are the total revenues from streaming sources for each film.

- 'Most lucrative films' refers to films with the highest gross revenue;
- 'Jewels' and 'gems' are metaphors for the top-grossing films;
- 'Box office treasure' refers to the gross revenue of the films;
- 'Shining stars' refers to the films with high ratings.

- "Total revenue" is the sum of domestic and international gross revenues;
- "Films released after 2010" refers to films with a release year greater than 2010;
- "Budget exceeding $100 million" refers to films with a budget greater than $100,000,000.

sql:
SELECT MAX(film_count) AS highest_film_count
FROM (
  SELECT COUNT(film_id) AS film_count
  FROM films
  GROUP BY studio_id
) AS studio_film_counts;

SELECT rating_value
FROM film_ratings
WHERE rating_value > 8 AND source = 'Rotten Tomatoes';

SELECT MAX(gross) AS highest_gross
FROM films
WHERE year = (SELECT MIN(year) FROM films);

external_knowledge:
- Revenue sources can include box office, streaming, and other distribution channels;
- Total revenue is the sum of all revenue amounts from different sources for each film;
- The query considers the gross revenue, budget, and average rating for each film to provide a comprehensive view.

sql:
SELECT production_cost
FROM film_budgets
WHERE budget_amount > 200000000;

SELECT AVG(revenue_amount) AS average_revenue
FROM film_revenues
WHERE source_id = 0 AND year = 2009;

external_knowledge:
- "shone brightly in the box office" refers to films with a gross revenue greater than 100 million;
- "audience ratings" refers to the average rating of the films;
- "released after 2010" means the films were released in the year 2011 or later.

- "Highly-rated" refers to films with a top rating from IMDb;
- "Above-average adjusted gross revenue" means the film's gross revenue, adjusted for inflation, is higher than the average adjusted gross revenue of all films;
- "IMDb" is a popular film rating source.
